"""
App-Icon für CardForge – eingebettete PNG-Raster pro Größe.
Generiert aus assets/icon.svg via scripts/build_icon.py
"""

from __future__ import annotations

import base64

from PySide6.QtCore import QByteArray
from PySide6.QtGui import QIcon, QImage, QPixmap

# PNG bytes (base64-encoded) per pixel size
_ICON_DATA: dict[int, bytes] = {
    16: base64.b64decode(
        ""
    ),
    24: base64.b64decode(
        ""
    ),
    32: base64.b64decode(
        ""
    ),
    48: base64.b64decode(
        ""
    ),
    64: base64.b64decode(
        ""
    ),
    128: base64.b64decode(
        ""
    ),
    256: base64.b64decode(
        ""
    ),
}


def get_app_icon() -> QIcon:
    """Return a QIcon with pre-rendered PNGs at common sizes."""
    icon = QIcon()
    for _size, data in _ICON_DATA.items():
        img = QImage.fromData(QByteArray(data), "PNG")  # type: ignore[arg-type]
        if not img.isNull():
            icon.addPixmap(QPixmap.fromImage(img), QIcon.Mode.Normal, QIcon.State.Off)
    return icon
